1	const sharp = require("sharp");
2	const fs = require("fs");
3	const path = require("path");
4	
5	const CANVAS_W = 1600;
6	const CANVAS_H = 1600;
7	const OUTPUT = "D:\\ClaudeWorkspace\\01_P4P\\主图素材\\连体衣_主图_标注版.png";
8	
9	// Product image coordinate system (800x800) → mapped positions
10	// Detected features from analysis:
11	const FEATURES = {
12	  zipper:       { px: 421, py: 420, label: "双向拉链\nTwo-way Zipper" },
13	  handCover:    { px: 100, py: 300, label: "手脚翻转覆盖\nFold-over Hand & Foot Cuffs" },
14	  footCover:    { px: 175, py: 690, label: "脚口翻转设计\nFold-over Foot Cuffs" },
15	  zipperGuard:  { px: 421, py: 140, label: "领口拉链盖保护\nZipper Guard Protection" },
16	  sizeChart:    { px: 320, py: 80,  label: "领口尺码标\nSize Chart Label" },
17	};
18	
19	// Annotation circle positions on canvas (where to place zoomed circles)
20	const CIRCLES = {
21	  zipper:      { cx: 1350, cy: 700, r: 100 },
22	  handCover:   { cx: 200,  cy: 550, r: 100 },
23	  footCover:   { cx: 300,  cy: 1350, r: 100 },
24	  zipperGuard: { cx: 1350, cy: 350, r: 100 },
25	  sizeChart:   { cx: 800,  cy: 1480, r: 80 },
26	};
