28	// Product placement on canvas
29	const PROD_SCALE = 0.95; // scale from 800 to canvas
30	const prodW = Math.round(800 * PROD_SCALE);
31	const prodH = Math.round(800 * PROD_SCALE);
32	const prodX = Math.round((CANVAS_W - prodW) / 2); // center
33	const prodY = Math.round(300);
34	
35	// Map product coordinate (800x800) to canvas coordinate
36	function mapToCanvas(px, py) {
37	  const scale = PROD_SCALE;
38	  return {
39	    x: Math.round(prodX + px * scale),
40	    y: Math.round(prodY + py * scale),
41	  };
42	}
43	
44	async function main() {
45	  const productPath = "C:\\Users\\Administrator\\Desktop\\222\\O1CN01L802zF1ETGQeGvjBS_!!2980740352-0-cib.jpg";
46	
47	  // Step 1: Create base white canvas
48	  console.log("Creating canvas...");
49	  const canvas = sharp({
50	    create: {
51	      width: CANVAS_W,
52	      height: CANVAS_H,
53	      channels: 4,
54	      background: { r: 252, g: 250, b: 240, alpha: 1 }, // warm white like reference
55	    },
56	  });
57	
58	  // Step 2: Place product image
59	  console.log("Placing product image...");
60	  const productResized = await sharp(productPath)
61	    .resize(prodW, prodH, { fit: "fill" })
62	    .toBuffer();
63	
64	  // Step 3: Create zoomed detail circles
65	  console.log("Creating detail callouts...");
66	  const composited = [];
67	  composited.push({ input: productResized, top: prodY, left: prodX });
68	
69	  const detailSize = 50; // extract region
70	  const circleDiam = 200; // display size
71	
72	  for (const [key, feat] of Object.entries(FEATURES)) {
73	    const circle = CIRCLES[key];
74	    const rx = Math.max(0, Math.min(750, feat.px - detailSize / 2));
75	    const ry = Math.max(0, Math.min(750, feat.py - detailSize / 2));
76	
77	    try {
78	      const detail = await sharp(productPath)
79	        .extract({ left: Math.round(rx), top: Math.round(ry), width: detailSize, height: detailSize })
80	        .resize(circleDiam, circleDiam)
81	        .toBuffer();
82	
83	      // Create circular mask
84	      const svgMask = Buffer.from(
85	        `<svg width="${circleDiam}" height="${circleDiam}">
86	          <circle cx="${circleDiam/2}" cy="${circleDiam/2}" r="${circleDiam/2}" fill="white"/>
87	        </svg>`
88	      );
89	
90	      const circled = await sharp(detail)
91	        .composite([{ input: svgMask, top: 0, left: 0, blend: "dest-in" }])
92	        .png()
93	        .toBuffer();
94	
95	      composited.push({
96	        input: circled,
97	        top: circle.cy - circle.r,
98	        left: circle.cx - circle.r,
99	      });
100	      console.log(`  ${key}: detail region (${rx},${ry}) → canvas (${circle.cx},${circle.cy})`);
101	    } catch (e) {
102	      console.error(`  ${key} failed: ${e.message}`);
103	    }
104	  }
105	
106	  // Step 4: Create SVG overlay with dotted lines, circle borders, text
107	  console.log("Creating annotation overlay...");
108	  let svgLines = `<svg width="${CANVAS_W}" height="${CANVAS_H}" xmlns="http://www.w3.org/2000/svg">`;
109	
110	  // Add a subtle top title
111	  svgLines += `<text x="800" y="60" text-anchor="middle" font-family="Arial,sans-serif" font-size="32" fill="#333" font-weight="bold">PRODUCT DETAILS — 婴儿连体衣 定制细节展示</text>`;
112	  svgLines += `<text x="800" y="95" text-anchor="middle" font-family="Arial,sans-serif" font-size="18" fill="#888">Baby Romper Customization Details</text>`;
113	
114	  // Dotted lines and circle annotations
115	  const lineColor = "rgba(80,160,80,0.8)";
116	  const lineWidth = 2.5;
117	  const dashArray = "8,6";
118	
119	  for (const [key, feat] of Object.entries(FEATURES)) {
120	    const canvasPt = mapToCanvas(feat.px, feat.py);
121	    const circle = CIRCLES[key];
122	
123	    // Dotted line from product feature to annotation circle edge
124	    const dx = circle.cx - canvasPt.x;
125	    const dy = circle.cy - canvasPt.y;
126	    const dist = Math.sqrt(dx * dx + dy * dy);
127	    if (dist === 0) continue;
128	
129	    // Find the point on the circle edge closest to the feature
130	    const edgeX = Math.round(circle.cx - (dx / dist) * circle.r);
131	    const edgeY = Math.round(circle.cy - (dy / dist) * circle.r);
132	
133	    svgLines += `<line x1="${canvasPt.x}" y1="${canvasPt.y}" x2="${edgeX}" y2="${edgeY}" stroke="${lineColor}" stroke-width="${lineWidth}" stroke-dasharray="${dashArray}" />`;
134	
135	    // Small dot at product feature point
136	    svgLines += `<circle cx="${canvasPt.x}" cy="${canvasPt.y}" r="5" fill="${lineColor}" />`;
137	
138	    // Circle border
139	    svgLines += `<circle cx="${circle.cx}" cy="${circle.cy}" r="${circle.r}" fill="none" stroke="${lineColor}" stroke-width="3" stroke-dasharray="6,4" />`;
140	
141	    // Label text below the circle (escape XML special chars)
142	    const lines = feat.label.split("\n");
143	    lines.forEach((line, i) => {
144	      const escaped = line.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
145	      svgLines += `<text x="${circle.cx}" y="${circle.cy + circle.r + 24 + i * 22}" text-anchor="middle" font-family="Arial,sans-serif" font-size="14" fill="#444" font-weight="bold">${escaped}</text>`;
146	    });
147	  }
148	
149	  // Add size chart area at bottom
150	  svgLines += `<rect x="600" y="1380" width="400" height="2" fill="#ddd" rx="1" />`;
151	
152	  // Footer
153	  svgLines += `<text x="800" y="1560" text-anchor="middle" font-family="Arial,sans-serif" font-size="13" fill="#aaa">Yiyang Xiaoxingxing Garment Co., Ltd | OEM/ODM Professional Baby Products Manufacturer</text>`;
154	
155	  svgLines += `</svg>`;
156	
157	  // Composite everything
158	  console.log("Rendering final image...");
159	  const result = await canvas
160	    .composite([
161	      ...composited,
162	      {
163	        input: Buffer.from(svgLines),
164	        top: 0,
165	        left: 0,
166	        blend: "over",
167	      },
168	    ])
169	    .png()
170	    .toFile(OUTPUT);
171	
172	  console.log(`\n✅ Done! Saved to: ${OUTPUT}`);
173	  console.log(`  Size: ${result.width}x${result.height}, ${result.size} bytes`);
174	}
175	
176	main().catch(console.error);
