29	async function sseFetch(url, body) {
30	  const res = await fetch(url, {
31	    method: "POST",
32	    headers: { "Content-Type": "application/json", Authorization: `Bearer ${API_KEY}` },
33	    body: JSON.stringify(body),
34	  });
35	
36	  if (!res.ok) {
37	    const text = await res.text();
38	    try {
39	      const j = JSON.parse(text);
40	      throw new Error(j.msg || j.message || text);
41	    } catch (e) {
42	      if (e.message !== text) throw e;
43	      throw new Error(`HTTP ${res.status}: ${text}`);
44	    }
45	  }
46	
47	  // Parse SSE stream
48	  const reader = res.body.getReader();
49	  const decoder = new TextDecoder();
50	  let buffer = "";
51	
52	  while (true) {
53	    const { done, value } = await reader.read();
54	    if (done) break;
55	    buffer += decoder.decode(value, { stream: true });
56	
57	    const lines = buffer.split("\n");
58	    buffer = lines.pop() || "";
59	
60	    for (const line of lines) {
61	      if (!line.startsWith("data: ")) continue;
62	      const jsonStr = line.slice(6);
63	      if (!jsonStr) continue;
64	      const data = JSON.parse(jsonStr);
65	
66	      if (data.status === "failed" || data.status === "error") {
67	        throw new Error(data.failure_reason || data.error || "Generation failed");
68	      }
69	      if (data.status === "succeeded" && data.results?.length > 0) {
70	        return data;
71	      }
72	    }
73	  }
74	  throw new Error("Stream ended without result");
75	}
76	
77	server.setRequestHandler(ListToolsRequestSchema, async () => ({
78	  tools: [
79	    {
80	      name: "generate_image",
81	      description: "使用 GrsAI 生成图像（Nano Banana / GPT Image 等模型）",
82	      inputSchema: {
83	        type: "object",
84	        properties: {
85	          model: {
86	            type: "string",
87	            description: "模型: nano-banana, nano-banana-pro, gpt-image-2 等",
88	            default: "nano-banana",
89	          },
90	          prompt: { type: "string", description: "图像描述提示词" },
91	          aspectRatio: {
92	            type: "string", description: "比例: 1:1, 16:9, 9:16, 4:3, 3:4",
93	            default: "1:1",
94	          },
95	          filename: {
96	            type: "string", description: "文件名前缀，默认自动生成",
97	          },
98	        },
99	        required: ["prompt"],
100	      },
101	    },
102	  ],
103	}));
104	
105	server.setRequestHandler(CallToolRequestSchema, async (request) => {
106	  if (request.params.name !== "generate_image") {
107	    throw new Error(`Unknown tool: ${request.params.name}`);
108	  }
109	
110	  const args = request.params.arguments;
111	  const model = args.model || "nano-banana";
112	  const prompt = args.prompt;
113	  const aspectRatio = args.aspectRatio || "1:1";
114	  const prefix = args.filename || `grsai_${model.replace(/[^a-z0-9]/gi, "_")}`;
115	  if (!prompt) throw new Error("prompt is required");
116	
117	  // Determine endpoint based on model
118	  const isPathModel = ["nano-banana", "nano-banana-pro", "nano-banana-2", "nano-banana-fast"].includes(model);
119	  const url = isPathModel
120	    ? `${API_BASE}/v1/draw/${model}`
121	    : `${API_BASE}/v1/draw/completions`;
122	
123	  const body = isPathModel
124	    ? { model, prompt, aspectRatio }
125	    : { model, prompt, size: aspectRatio };
126	
127	  const result = await sseFetch(url, body);
128	
129	  // Download images
130	  const savedPaths = [];
131	  for (const img of (result.results || [])) {
132	    const imgUrl = img.url || img.image;
133	    if (!imgUrl) continue;
134	
135	    const imgRes = await fetch(imgUrl);
136	    const buf = Buffer.from(await imgRes.arrayBuffer());
137	    const ext = (imgUrl.match(/\.(png|jpg|jpeg|webp)/i) || [,"png"])[1];
138	    const name = `${prefix}_${ts()}.${ext}`;
139	    const fp = path.join(SAVE_DIR, name);
140	    fs.writeFileSync(fp, buf);
141	    savedPaths.push(fp);
142	  }
143	
144	  return {
145	    content: [{
146	      type: "text",
147	      text: JSON.stringify({ savedPaths, status: "succeeded" }, null, 2),
148	    }],
149	  };
150	});
151	
152	process.on("SIGINT", async () => { await server.close(); process.exit(0); });
153	const transport = new StdioServerTransport();
154	await server.connect(transport);
