4	async function detectFeatures(filePath, label) {
5	  const meta = await sharp(filePath).metadata();
6	  const { width, height } = meta;
7	  const raw = await sharp(filePath).raw().toBuffer();
8	
9	  console.log(`\n========== ${label} 特征检测 ==========`);
10	
11	  function getPixel(x, y) {
12	    x = Math.round(x); y = Math.round(y);
13	    if (x < 0 || x >= width || y < 0 || y >= height) return null;
14	    const idx = (y * width + x) * 3;
15	    return { r: raw[idx], g: raw[idx + 1], b: raw[idx + 2] };
16	  }
17	
18	  // 1. Find vertical edges (potential zipper line in center)
19	  console.log("\n--- 垂直边缘检测(找拉链) ---");
20	  const centerX = Math.floor(width / 2);
21	  for (let y = 100; y < height - 100; y += 50) {
22	    let maxDiff = 0, maxX = 0;
23	    // Scan horizontally around center for sharp color transitions
24	    for (let x = centerX - 100; x < centerX + 100; x += 2) {
25	      const c1 = getPixel(x - 3, y);
26	      const c2 = getPixel(x + 3, y);
27	      if (!c1 || !c2) continue;
28	      const diff = Math.abs(c1.r - c2.r) + Math.abs(c1.g - c2.g) + Math.abs(c1.b - c2.b);
29	      if (diff > maxDiff) { maxDiff = diff; maxX = x; }
30	    }
31	    if (maxDiff > 30) {
32	      console.log(`  y=${y}: 最强垂直边缘 x=${maxX} (对比度=${maxDiff}) — ${maxDiff > 50 ? "拉链/缝线" : "可能是褶皱"}`);
33	    }
34	  }
35	
36	  // 2. Find horizontal edges (potential collar, hem, cuffs)
37	  console.log("\n--- 水平边缘检测(找领口/袖口/脚口) ---");
38	  for (let x = 100; x < width - 100; x += 100) {
39	    let maxDiff = 0, maxY = 0;
40	    for (let y = 20; y < height - 20; y += 2) {
41	      const c1 = getPixel(x, y - 3);
42	      const c2 = getPixel(x, y + 3);
43	      if (!c1 || !c2) continue;
44	      const diff = Math.abs(c1.r - c2.r) + Math.abs(c1.g - c2.g) + Math.abs(c1.b - c2.b);
45	      if (diff > maxDiff) { maxDiff = diff; maxY = y; }
46	    }
47	    if (maxDiff > 40) {
48	      const zone = maxY < height * 0.3 ? "领口/肩部" : maxY < height * 0.5 ? "胸部" : maxY < height * 0.7 ? "腹部" : "脚口/底部";
49	      console.log(`  x=${x}: 最强水平边缘 y=${maxY} (对比度=${maxDiff}) — ${zone}`);
50	    }
51	  }
52	
53	  // 3. Find extremity boundaries (leftmost/rightmost non-white pixels per row)
54	  console.log("\n--- 产品轮廓检测 ---");
55	  const leftEdges = [], rightEdges = [], topEdges = [], bottomEdges = [];
56	
57	  function isProduct(r, g, b) {
58	    // Product is warm beige tones; ignore pure white
59	    return !(r > 240 && g > 240 && b > 240);
60	  }
61	
62	  // Find leftmost product pixel per row
63	  for (let y = 50; y < height - 50; y += 10) {
64	    for (let x = 5; x < width; x += 2) {
65	      const c = getPixel(x, y);
66	      if (c && isProduct(c.r, c.g, c.b)) {
67	        // Check if this is truly edge (neighbor is significantly different)
68	        const cLeft = getPixel(x - 5, y);
69	        if (cLeft && !isProduct(cLeft.r, cLeft.g, cLeft.b)) {
70	          leftEdges.push({ x, y });
71	        }
72	        break;
73	      }
74	    }
75	    // Find rightmost
76	    for (let x = width - 5; x > 0; x -= 2) {
77	      const c = getPixel(x, y);
78	      if (c && isProduct(c.r, c.g, c.b)) {
79	        const cRight = getPixel(x + 5, y);
80	        if (cRight && !isProduct(cRight.r, cRight.g, cRight.b)) {
81	          rightEdges.push({ x, y });
82	        }
83	        break;
84	      }
85	    }
86	  }
87	
88	  if (leftEdges.length > 0) {
89	    const minX = Math.min(...leftEdges.map(e => e.x));
90	    const yAtMinX = leftEdges.find(e => e.x === minX)?.y || 0;
91	    console.log(`  最左边缘: x=${minX} (y≈${yAtMinX}) — ${yAtMinX < height*0.4 ? "左袖口" : "左裤脚"}`);
92	  }
93	  if (rightEdges.length > 0) {
94	    const maxX = Math.max(...rightEdges.map(e => e.x));
95	    const yAtMaxX = rightEdges.find(e => e.x === maxX)?.y || 0;
96	    console.log(`  最右边缘: x=${maxX} (y≈${yAtMaxX}) — ${yAtMaxX < height*0.4 ? "右袖口" : "右裤脚"}`);
97	  }
98	
99	  // Find topmost/bottommost product pixels
100	  for (let x = centerX - 150; x <= centerX + 150; x += 10) {
101	    for (let y = 5; y < height; y += 2) {
102	      const c = getPixel(x, y);
103	      if (c && isProduct(c.r, c.g, c.b)) {
104	        topEdges.push({ x, y });
105	        break;
106	      }
107	    }
108	    for (let y = height - 5; y > 0; y -= 2) {
109	      const c = getPixel(x, y);
110	      if (c && isProduct(c.r, c.g, c.b)) {
111	        bottomEdges.push({ x, y });
112	        break;
113	      }
114	    }
115	  }
116	
117	  if (topEdges.length > 0) {
118	    const avgY = Math.round(topEdges.reduce((s, e) => s + e.y, 0) / topEdges.length);
119	    console.log(`  产品顶部: y≈${avgY} (领口位置)`);
120	  }
121	  if (bottomEdges.length > 0) {
122	    const avgY = Math.round(bottomEdges.reduce((s, e) => s + e.y, 0) / bottomEdges.length);
123	    console.log(`  产品底部: y≈${avgY} (脚口位置)`);
124	  }
125	
126	  // 4. Color analysis for specific features
127	  console.log("\n--- 颜色特征区域 ---");
128	  // Darker regions might be zipper, labels, etc.
129	  const darkRegions = [];
130	  for (let y = 50; y < height - 50; y += 15) {
131	    for (let x = 50; x < width - 50; x += 15) {
132	      const c = getPixel(x, y);
133	      if (!c) continue;
134	      const brightness = (c.r + c.g + c.b) / 3;
135	      if (brightness < 120) {
136	        // Check if it's part of a larger dark region
137	        let darkCount = 0;
138	        for (let dy = -10; dy <= 10; dy += 5)
139	          for (let dx = -10; dx <= 10; dx += 5) {
140	            const nc = getPixel(x + dx, y + dy);
141	            if (nc && (nc.r + nc.g + nc.b) / 3 < 150) darkCount++;
142	          }
143	        if (darkCount > 5) darkRegions.push({ x, y, brightness });
144	      }
145	    }
146	  }
147	
148	  const darkClusters = [];
149	  for (const d of darkRegions) {
150	    let found = false;
151	    for (const cl of darkClusters) {
152	      if (Math.abs(cl.x - d.x) < 30 && Math.abs(cl.y - d.y) < 30) {
153	        cl.count++; cl.x = (cl.x * cl.count + d.x) / (cl.count + 1);
154	        cl.y = (cl.y * cl.count + d.y) / (cl.count + 1);
155	        found = true; break;
156	      }
157	    }
158	    if (!found) darkClusters.push({ x: d.x, y: d.y, count: 1 });
159	  }
160	
161	  const significantDark = darkClusters.filter(c => c.count > 3).sort((a, b) => a.y - b.y);
162	  for (const d of significantDark) {
163	    const zone = d.y < height*0.3 ? "领口" : d.y < height*0.45 ? "胸部" : d.y < height*0.6 ? "腹部/拉链" : d.y < height*0.8 ? "大腿" : "脚口";
164	    const side = d.x < width*0.3 ? "偏左" : d.x > width*0.7 ? "偏右" : "居中";
165	    console.log(`  深色区域 (${Math.round(d.x)},${Math.round(d.y)}) ${zone}/${side} 亮度=${d.count}`);
